// SPDX-License-Identifier: MIT
pragma solidity 0.8.20;

contract PresaleMint {
    address public owner;

    enum State { PresaleLive, SaleLive, SaleClosed }
    State public currentState;

    mapping(address => bool) public presalerList;

    uint256 public presaleAmountMinted;
    uint256 public publicAmountMinted;

    event Whitelisted(address indexed user, bool status);
    event SaleStateChanged(State newState);
    event PresalePurchase(address indexed buyer, uint256 amount);
    event PublicPurchase(address indexed buyer, uint256 amount);

    error NotOwner();
    error InvalidState();
    error NotWhitelisted();

    modifier onlyOwner() {
        if (msg.sender != owner) revert NotOwner();
        _;
    }

    modifier onlyState(State requiredState) {
        if (currentState != requiredState) revert InvalidState();
        _;
    }

    constructor() {
        owner = msg.sender;
        currentState = State.PresaleLive;
    }

    function whitelist(address user, bool status) external onlyOwner {
        presalerList[user] = status;
        emit Whitelisted(user, status);
    }

    function toggleSale() external onlyOwner {
        if (currentState == State.PresaleLive) {
            currentState = State.SaleLive;
        } else if (currentState == State.SaleLive) {
            currentState = State.SaleClosed;
        } else {
            revert InvalidState();
        }
        emit SaleStateChanged(currentState);
    }

    function presaleBuy() external payable onlyState(State.PresaleLive) {
        if (!presalerList[msg.sender]) revert NotWhitelisted();
        presaleAmountMinted++;
        emit PresalePurchase(msg.sender, msg.value);
    }

    function buy() external payable onlyState(State.SaleLive) {
        publicAmountMinted++;
        emit PublicPurchase(msg.sender, msg.value);
    }
}
